// src/components/InternshipModal.jsx
import React, { useState, useEffect } from 'react';
import './InternshipModal.css';

const InternshipModal = ({ show, onClose, onSave, initialData }) => {
  const [formData, setFormData] = useState({
    title: '',
    company: '',
    location: '',
    stipend: '',
    duration: '',
    description: '',
    skills: '',
    applyLink: ''
  });

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    }
  }, [initialData]);

  if (!show) return null;

  const handleChange = (e) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave(formData);
    onClose();
  };

  return (
    <div className="modal-overlay">
      <div className="modal">
        <h2>{initialData ? 'Edit Internship' : 'Add Internship'}</h2>
        <form onSubmit={handleSubmit}>
          <input name="title" placeholder="Title" value={formData.title} onChange={handleChange} required />
          <input name="company" placeholder="Company" value={formData.company} onChange={handleChange} required />
          <input name="location" placeholder="Location" value={formData.location} onChange={handleChange} required />
          <input name="stipend" placeholder="Stipend" value={formData.stipend} onChange={handleChange} />
          <input name="duration" placeholder="Duration" value={formData.duration} onChange={handleChange} />
          <input name="skills" placeholder="Skills (comma-separated)" value={formData.skills} onChange={handleChange} />
          <textarea name="description" placeholder="Description" value={formData.description} onChange={handleChange} />
          <input name="applyLink" placeholder="Apply Link (optional)" value={formData.applyLink} onChange={handleChange} />
          <div className="modal-actions">
            <button type="submit">Save</button>
            <button type="button" className="cancel" onClick={onClose}>Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default InternshipModal;
